    19→const MyOrdersCashback = () => {
    20→  const [isRefreshing, setIsRefreshing] = useState(false);
    21→
    22→  const modalizeRefFilters = useRef<PropsModalizeRef>(null);
    23→  const emptyImage =
    24→    'https://image.mkt-semparar.com.br/lib/fe2f117170640475721171/m/1/shopping_cart.png';
    25→
    26→  const SKELETON_COUNT = 3;
    27→  const { width } = Dimensions.get('window');
    28→
    29→  const navigation = useNavigation<NavigationProp<PropsRootStack>>();
    30→
    31→  const { pointsExtract, pointsExtractActions } = useRootStore(
    32→    useShallow(state => ({
    33→      pointsExtract: state.pointsExtract,
    34→      pointsExtractActions: state.pointsExtractActions,
    35→    })),
    36→  );
    37→
    38→  const getFormatDate = (iso?: string) => {
    39→    if (!iso) return '';
    40→    const date = parseISO(iso);
    41→    return format(date, 'dd/MM/yyyy');
    42→  };
    43→
    44→  const getFilterGroups: FilterGroup[] = useMemo(() => {
    45→    return [
    46→      {
    47→        label: 'Períodos',
    48→        options: [
    49→          {
    50→            label: '7 dias',
    51→            value: 0,
    52→          },
    53→          {
    54→            label: '15 dias',
    55→            value: 1,
    56→          },
    57→          {
    58→            label: '30 dias',
    59→            value: 2,
    60→          },
    61→          {
    62→            label: '60 dias',
    63→            value: 3,
    64→          },
    65→          {
    66→            label: '90 dias',
    67→            value: 4,
    68→          },
    69→        ],
    70→      },
    71→      {
    72→        label: 'Tipos de lançamentos',
    73→        options: [
    74→          {
    75→            label: 'Mais recentes',
    76→            value: 'ASC',
    77→          },
    78→          {
    79→            label: 'Mais antigas',
    80→            value: 'DESC',
    81→          },
    82→        ],
    83→      },
    84→    ];
    85→  }, []);
    86→
    87→  const handleOpenFilters = () => {
    88→    eventSelectContent({
    89→      content_type: 'cta',
    90→      content_id: 'filtro_pedidos',
    91→      location_1: 'monetizacao',
    92→      location_2: 'hub_recompensas_spmais',
    93→      location_3: 'meus_pedidos',
    94→    });
    95→
    96→    modalizeRefFilters.current?.open?.();
    97→  };
    98→
    99→  const handleDetailsOrders = (
   100→    transactionId: string,
   101→    type?: string,
   102→    icon?: string,
   103→    status?: string,
   104→    origination?: string,
   105→  ) => {
   106→    eventSelectContent({
   107→      content_type: 'cta',
   108→      content_id: 'detalhe_pedido',
   109→      location_1: 'monetizacao',
   110→      location_2: 'hub_recompensas_spmais',
   111→      location_3: 'meus_pedidos',
   112→    });
   113→
   114→    navigation.navigate('MyOrdersDetails', {
   115→      transactionId,
   116→      type,
   117→      icon,
   118→      status,
   119→      origination,
   120→    });
   121→  };
   122→
   123→  const myOrders = pointsExtract?.extractData?.transactions || [];
   124→
   125→  const isLoading = pointsExtract.status === PointsExtractStatus.LOADING;
   126→  const isError = pointsExtract.status === PointsExtractStatus.ERROR;
   127→
   128→  const handleGoBack = () => {
   129→    pointsExtractActions.clearTransactionsFilters();
   130→    pointsExtractActions.reset();
   131→    navigation.goBack();
   132→  };
   133→
   134→  const handleRefresh = async () => {
   135→    setIsRefreshing(true);
   136→    await getPointsExtract({ type: 'Resgate' });
   137→    setIsRefreshing(false);
   138→  };
   139→
   140→  const hasFocused = useRef(false);
   141→  useFocusEffect(
   142→    React.useCallback(() => {
   143→      if (!hasFocused.current) {
   144→        eventScreenViewV3(
   145→          'meus_pedidos',
   146→          'hub_recompensas_spmais',
   147→          'monetizacao',
   148→          {
   149→            location_1: 'monetizacao',
   150→            location_2: 'hub_recompensas_spmais',
   151→            location_3: 'meus_pedidos',
   152→          },
   153→        );
   154→        pointsExtractActions.clearTransactionsFilters();
   155→        pointsExtractActions.reset();
   156→        getPointsExtract({ type: 'Resgate' });
   157→        hasFocused.current = true;
   158→      }
   159→      return () => {
   160→        hasFocused.current = false;
   161→      };
   162→    }, [pointsExtractActions]),
   163→  );
   164→
   165→  return (
   166→    <MyOrdersCashbackView
   167→      myOrders={myOrders}
   168→      emptyImage={emptyImage}
   169→      isLoading={isLoading}
   170→      isError={isError}
   171→      filterGroups={getFilterGroups}
   172→      modalizeRefFilters={modalizeRefFilters}
   173→      formatDate={getFormatDate}
   174→      handleGoBack={handleGoBack}
   175→      handleOpenFilters={handleOpenFilters}
   176→      handleDetailsOrders={handleDetailsOrders}
   177→      isRefreshing={isRefreshing}
   178→      handleRefresh={handleRefresh}
   179→      skeletonCount={SKELETON_COUNT}
   180→      screenWidth={width}
   181→    />
   182→  );
   183→};
   184→
   185→export default MyOrdersCashback;
   186→

